func Test_VisitorAudioCustom(t *testing.T) {
	// Visitor replaces audio element with custom output
	visitor := &testVisitorVisitorAudioCustom{}
	opts := &htmd.ConversionOptions{}
	opts.Visitor = visitor
	result, err := htmd.Convert(`<p>Listen to this: <audio src="podcast.mp3" controls></audio></p>`, opts)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	var content string
	if result.Content != nil {
		content = string(*result.Content)
	}
	if !strings.Contains(string(content), `[AUDIO: podcast.mp3]`) {
		t.Errorf("expected to contain %s, got %v", `[AUDIO: podcast.mp3]`, content)
	}
	if !strings.Contains(string(content), `Listen to this:`) {
		t.Errorf("expected to contain %s, got %v", `Listen to this:`, content)
	}
}

